         <a href="https://email.mg2.substack.com/c/eJxFkE1uxCAMhU8zLCPM3yQLFt30GhEBJ4MmgRScqdLTl2YWlSzb0pP99D7vCJdcTrvnSuyvjXTuaBN-1xWJsLCjYhljsGBEL7UaWLAqQK97Fus4F8TNxdVSOZDtx7RG7yjmdF1wLjR7WK-D8D5I76WY_B2CUdqpEIZhMDNo_fZ1R4iYPFp8YTlzQrbaB9Feb_LjJj5b7eGndj63jYvJzYrrOwelxN07CDB7oY2RZp55YNEKLoCD6EFqrU0HnVcv1M8v0jLfFN8W0dVjquT8s_3cWLEp05RLTEuTnw-34XoJLdTY5nakSOeIyU0rhndeemO7CIwLJiwNZxgdNVgAvRKgjWrErnwNiIRB9WaQrDmH3K7Sv-kvXoKC_g" style="color: #1a1a1a; text-decoration: underline;">
